import React, { useState } from "react";
import Dice from "react-dice-roll";

// Board image in public folder
const boardImage = "/torahpoly_board.png";

// Sample Bereshit Card
const bereshitCard = {
  name: "Bereshit",
  questions: [
    { question: "What day was Adam born?", answer: "The 6th day", points: 20 },
    { question: "What day was not 'good' but 'very' good?", answer: "The 6th day", points: 20 },
    { question: "Where do we see adding is sometimes subtracting?", answer: "Adam added 'don't touch' the tree. The snake used this to fool Chava.", points: 20 },
  ],
};

// Har HaBayit Card
const harHaBayitCard = {
  name: "Har HaBayit",
  questions: [
    { question: 'Which items were housed in the Kodesh ("holy") chamber?', answer: "The showbread table, menorah, and incense altar", points: 300 },
    { question: "What is the OJ associated with the Omer, the Two Loaves and the Lechem Hapanim?", answer: `That never was a disqualifying defect found in any of these 3 holy offerings. Explanation: 
a. The Omer, the barley offering brought on the 16th of Nissan, released the new crop for eating if a defect occurred, they wouldn't be able to bring the offering on that day and the new crop would have remained forbidden for the entire year!
b. If there was a defect in the Two Loaves brought on Shavuos, we would have been unable to bring this offering, and would then have been unable to use the new wheat crop for minchah on the mizbe'ach.
c. If a defect were found on the 12 loaves of the Lechem HaPanim that were baked before Shabbos, no new loaves would have been able to be set on the Shulchan until the following week.`, points: 600 },
  ],
};

// Mazal Card
const mazalCard = {
  name: "Mazal",
  text: `You had a dream of buried treasure in a far-off city. You travelled there and found the spot and began digging. A policeman stopped you, and after you explained the story, he said he had the same dream of a treasure buried under the floorboards of a tailor shop. You realized that he was describing your own house. You dropped the shovel and ran home to discover the treasure buried under your own bed.`,
  reward: 1000,
  rewardType: "money",
};

function CardQA({ card, onFinish }) {
  const [currentQ, setCurrentQ] = useState(0);
  const [showAnswer, setShowAnswer] = useState(false);
  const [accepted, setAccepted] = useState(Array(card.questions ? card.questions.length : 0).fill(false));
  const isMazal = card.name === "Mazal";

  const toggleAnswer = () => setShowAnswer((v) => !v);
  const acceptCorrect = () => setAccepted((prev) => { const copy = [...prev]; copy[currentQ] = true; return copy; });
  const prevQuestion = () => { setShowAnswer(false); setCurrentQ((i) => (i > 0 ? i - 1 : i)); };
  const nextQuestion = () => { setShowAnswer(false); setCurrentQ((i) => (i < card.questions.length - 1 ? i + 1 : i)); };
  const totalPoints = accepted.reduce((sum, val, i) => (val ? sum + card.questions[i].points : sum), 0);
  const allCorrect = accepted.every((val) => val === true);

  return (
    <div style={styles.qaContainer}>
      <h2>{card.name} Card</h2>

      {isMazal ? (
        <>
          <p style={{ fontWeight: "bold", whiteSpace: "pre-wrap" }}>{card.text}</p>
          {!showAnswer ? <button onClick={toggleAnswer} style={styles.button}>Reveal Mazal</button> :
            <p style={{ color: "green", fontWeight: "bold" }}>
              {card.rewardType === "money" ? `You won $${card.reward}!` : `You gained ${card.reward} Zchut points!`}
            </p>
          }
          <button onClick={() => onFinish(true, card.reward, card.rewardType)} style={{ ...styles.button, marginTop: 20 }}>Close</button>
        </>
      ) : (
        <>
          <p>Question {currentQ + 1} of {card.questions.length}</p>
          <div style={styles.questionBox}>
            <p style={{ fontWeight: "bold" }}>{card.questions[currentQ].question}</p>
            {showAnswer ? <p style={styles.answer}>{card.questions[currentQ].answer}</p> :
              <button onClick={toggleAnswer} style={styles.button}>Reveal Answer</button>
            }
          </div>
          <div style={{ marginTop: 10 }}>
            <button onClick={prevQuestion} disabled={currentQ === 0} style={styles.button}>Previous Question</button>
            <button onClick={nextQuestion} disabled={currentQ === card.questions.length - 1} style={{ ...styles.button, marginLeft: 10 }}>Next Question</button>
          </div>
          <div style={{ marginTop: 20 }}>
            {!accepted[currentQ] && showAnswer && <button onClick={acceptCorrect} style={styles.acceptButton}>Accept Correct (Add {card.questions[currentQ].points} Zchut)</button>}
            {accepted[currentQ] && <p style={{ color: "green", fontWeight: "bold" }}>Accepted Correct ✔</p>}
          </div>
          <div style={{ marginTop: 30 }}>
            <p>Total Zchut Points Earned: <strong>{totalPoints}</strong></p>
            {allCorrect ? <p style={{ color: "blue", fontWeight: "bold" }}>All questions answered correctly! You can proceed to the next card.</p> :
              <p>You can finish now with current points or continue answering.</p>
            }
          </div>
          <button onClick={() => onFinish(allCorrect, totalPoints, "zchut")} style={{ ...styles.button, marginTop: 20 }}>Finish Q&A</button>
        </>
      )}
    </div>
  );
}

function App() {
  // --- PLAYER SETUP ---
  const maxPlayers = 7;
  const availableColors = ["black", "#800080", "blue", "brown", "orange", "red", "green"];
  const [players, setPlayers] = useState([]);
  const [newPlayerName, setNewPlayerName] = useState("");
  const [newPlayerColor, setNewPlayerColor] = useState("");
  const [gameStarted, setGameStarted] = useState(false);

  // --- GAME STATE ---
  const [boardRotation, setBoardRotation] = useState(0);
  const [currentPlayerIndex, setCurrentPlayerIndex] = useState(0);
  const [qaMode, setQaMode] = useState(false);
  const [currentCard, setCurrentCard] = useState(null);

  // --- PLAYER HANDLERS ---
  const addPlayer = () => {
    if (!newPlayerName || !newPlayerColor) return;
    if (players.some((p) => p.color === newPlayerColor)) { alert("Color already taken!"); return; }
    setPlayers([...players, { name: newPlayerName, color: newPlayerColor, position: 0, zchutPoints: 1000, money: 2000 }]);
    setNewPlayerName("");
    setNewPlayerColor("");
  };

  const startGame = () => {
    if (players.length < 2) { alert("At least 2 players required."); return; }
    setGameStarted(true);
  };

  const rotateBoard = () => setBoardRotation((prev) => (prev + 90) % 360);
  const startQA = (card) => { setCurrentCard(card); setQaMode(true); };
  const finishQA = (allCorrect, points, rewardType = "zchut") => {
    setQaMode(false);
    let updatedPlayers = [...players];
    if (rewardType === "zchut") updatedPlayers[currentPlayerIndex].zchutPoints += points;
    else updatedPlayers[currentPlayerIndex].money += points;
    setPlayers(updatedPlayers);
    setCurrentCard(null);
  };

  const rollDice = (val) => {
    let updatedPlayers = [...players];
    updatedPlayers[currentPlayerIndex].position += val;
    setPlayers(updatedPlayers);
  };

  const endTurn = () => setCurrentPlayerIndex((prev) => (prev + 1) % players.length);

  return (
    <div style={styles.container}>
      <h1>TorahPoly Monopoly Game</h1>

      {!gameStarted ? (
        <>
          {players.length < maxPlayers && (
            <div style={styles.inputRow}>
              <input type="text" placeholder="Player Name" value={newPlayerName} onChange={(e) => setNewPlayerName(e.target.value)} style={styles.input} />
              <select value={newPlayerColor} onChange={(e) => setNewPlayerColor(e.target.value)} style={styles.input}>
                <option value="">Choose Color</option>
                {availableColors.filter((c) => !players.some((p) => p.color === c)).map((color) => (
                  <option key={color} value={color}>{color}</option>
                ))}
              </select>
              <button onClick={addPlayer} style={styles.button}>Add Player</button>
            </div>
          )}
          <h2>Joined Players ({players.length}/{maxPlayers})</h2>
          <ul>
            {players.map((p, index) => (
              <li key={index} style={{ color: p.color, fontWeight: index === currentPlayerIndex ? "bold" : "normal" }}>
                {p.name} ({p.color})
              </li>
            ))}
          </ul>
          <button onClick={startGame} style={{ ...styles.button, marginTop: 20 }}>Start Game</button>
        </>
      ) : (
        <>
          <div style={{ marginBottom: 20 }}>
            <h2>Players</h2>
            <ul>
              {players.map((p, index) => (
                <li key={index} style={{ color: p.color, fontWeight: index === currentPlayerIndex ? "bold" : "normal" }}>
                  {p.name} - Position: {p.position}, Zchut: {p.zchutPoints}, Money: ${p.money} {index === currentPlayerIndex && "(Your Turn)"}
                </li>
              ))}
            </ul>
          </div>

          <div style={{ position: "relative", display: "inline-block", marginBottom: 20, transform: `rotate(${boardRotation}deg)`, transition: "transform 0.5s ease" }}>
            <img src={boardImage} alt="Game Board" style={{ width: "100%", maxWidth: 1200, border: "2px solid #333", borderRadius: 12 }} />
          </div>

          <button onClick={rotateBoard} style={styles.button}>Rotate Board 90°</button>

          <div style={{ marginTop: 20 }}>
            <h2>Roll Dice</h2>
            <div style={{ display: "flex", justifyContent: "center", gap: 20 }}>
              <Dice sides={6} onRoll={rollDice} faceColor="#007bff" dotColor="#fff" rollTime={1} />
            </div>
            <button onClick={endTurn} style={{ ...styles.button, marginTop: 15 }}>End Turn</button>
          </div>
        </>
      )}

      {qaMode && currentCard && <CardQA card={currentCard} onFinish={finishQA} />}
    </div>
  );
}

const styles = {
  container: { fontFamily: "Arial, sans-serif", padding: 20, backgroundColor: "#f0f2f5", minHeight: "100vh", textAlign: "center" },
  button: { backgroundColor: "#007bff", color: "white", border: "none", borderRadius: 8, padding: "10px 20px", fontSize: 16, cursor: "pointer" },
  input: { fontSize: 16, padding: "5px 10px", borderRadius: 4, border: "1px solid #ccc" },
  qaContainer: { fontFamily: "Arial, sans-serif", maxWidth: 500, margin: "20px auto", padding: 20, border: "2px solid #333", borderRadius: 12, backgroundColor: "#fff", textAlign: "left" },
  questionBox: { marginTop: 10, padding: 10, border: "1px solid #333", borderRadius: 6, backgroundColor: "#f9f9f9" },
  answer: { color: "green", fontWeight: "bold", marginTop: 10 },
  acceptButton: { backgroundColor: "#28a745", color: "#fff", border: "none", borderRadius: 6, padding: "8px 12px", cursor: "pointer", fontWeight: "bold" },
  inputRow: { display: "flex", justifyContent: "center", gap: 10, marginBottom: 20 },
};

export default App;
